using System;
using System.Collections.Generic;
using GTA;
using GTA.Math;
using GTA.Native;
using ModProject.LiveStudio;

namespace ModProject
{
    public class Mod : Script
    {
        private LiveStudioClient _client;
        private readonly HashSet<int> _spawnedVehicles = new HashSet<int>();

        public Mod()
        {
            Tick += OnTick;
            Aborted += OnAborted;

            _client = new LiveStudioClient(
                onEvent: HandleEvent,
                onLog: msg => MainThreadDispatcher.Enqueue(() => GTA.UI.Notification.Show("~y~" + msg))
            );
            _client.Start();
        }

        private void OnTick(object sender, EventArgs e)
        {
            MainThreadDispatcher.DrainOnTick();
        }

        private void OnAborted(object sender, EventArgs e)
        {
            Cleanup();
        }

        private void HandleEvent(object sender, object e)
        {
            if (e is ChatEvent chat)
            {
                HandleChat(chat);
            }
            else if (e is GiftEvent gift)
            {
                HandleGift(gift);
            }
        }

        private void HandleChat(ChatEvent chat)
        {
            string content = chat.Content?.Trim() ?? "";
            if (string.Equals(content, "ping", StringComparison.OrdinalIgnoreCase))
            {
                MainThreadDispatcher.Enqueue(() =>
                {
                    Ped player = Game.Player.Character;
                    if (player == null || !player.Exists()) return;

                    int currentArmor = player.Armor;
                    int maxArmor = 100;
                    int newArmor = Math.Min(currentArmor + 25, maxArmor);
                    player.Armor = newArmor;

                    GTA.UI.Screen.ShowSubtitle("Ping! +25 Armor", 3000);
                });
            }
        }

        private void HandleGift(GiftEvent gift)
        {
            if (gift.GiftId == "rose")
            {
                MainThreadDispatcher.Enqueue(() =>
                {
                    Ped player = Game.Player.Character;
                    if (player == null || !player.Exists()) return;

                    Vector3 playerPos = player.Position;
                    Vector3 spawnPos = World.GetNextPositionOnStreet(playerPos);
                    if (spawnPos == Vector3.Zero)
                    {
                        spawnPos = playerPos;
                    }

                    Model policeModel = new Model(VehicleHash.Police);
                    if (!policeModel.IsLoaded)
                    {
                        policeModel.Request(1000);
                    }

                    if (!policeModel.IsLoaded) return;

                    Vehicle spawned = World.CreateVehicle(policeModel, spawnPos, player.Heading);
                    if (spawned == null || !spawned.Exists()) return;

                    spawned.IsInvincible = true;
                    spawned.CanBeVisiblyDamaged = false;
                    spawned.IsPersistent = true;

                    _spawnedVehicles.Add(spawned.Handle);
                });
            }
        }

        private void Cleanup()
        {
            foreach (int handle in _spawnedVehicles)
            {
                Vehicle veh = new Vehicle(handle);
                if (veh != null && veh.Exists())
                {
                    veh.IsPersistent = false;
                    veh.Delete();
                }
            }
            _spawnedVehicles.Clear();

            _client?.Dispose();
            _client = null;
        }
    }
}
